      "effective_date": "2025-01-01",
      "expiry_date": null,
      "status": "current",
      "applicability_reason": "用于确定拆分报销的审批线AR-02(3000元)",
      "applicable_clauses": [
        {"article": "附件二", "rule": "审批权限表", "thresholds": [
          {"tier": "AR-01", "range": "0元 ≤ 金额 < 3000元", "approver": "部门经理"},
          {"tier": "AR-02", "range": "3000元 ≤ 金额 < 10000元", "approver": "部门经理+财务复核"},
          {"tier": "AR-03", "range": "10000元 ≤ 金额 < 50000元", "approver": "部门总经理"},
          {"tier": "AR-04", "range": "50000元 ≤ 金额 < 200000元", "approver": "分管副总"},
          {"tier": "AR-05", "range": "金额 ≥ 200000元", "approver": "总经理办公会"}
        ]}
      ]
    },
    {
      "policy_id": "04_travel_expense.md",
      "title": "XX证券差旅费管理办法",
      "doc_number": "XX证行规〔2025〕丁号",
      "effective_date": "2025-01-01",
      "expiry_date": null,
      "status": "current",
      "applicability_reason": "差旅住宿标准用于超标准报销(R3)检测",
      "applicable_clauses": [
        {"article": "第四条", "rule": "差旅住宿标准", "standards": "按职级和城市档位分级"}
      ]
    },
    {
      "policy_id": "05_training_expense.md",
      "title": "XX证券培训费管理办法",
      "doc_number": "XX证人规〔2025〕戊号",
      "effective_date": "2025-01-01",
      "expiry_date": null,
      "status": "current",
      "applicability_reason": "培训费和培训住宿标准用于超标准报销(R3)检测",
      "applicable_clauses": [
        {"article": "第二条", "rule": "培训课程费", "threshold": "每人每期不超过3500元"},
        {"article": "第三条", "rule": "内部培训综合费", "threshold": "每日不超过800元"},
        {"article": "第四条", "rule": "外部培训综合费", "threshold": "每日不超过1200元"},
        {"article": "第五条", "rule": "培训住宿标准", "thresholds": {"一类城市": 500, "二类城市": 420, "三类城市": 350}}
      ]
    },
    {
      "policy_id": "06_business_entertainment.md",
      "title": "XX证券业务招待费管理办法",
      "doc_number": "XX证客规〔2025〕己号",
      "effective_date": "2025-01-01",
      "expiry_date": null,
      "status": "current",
      "applicability_reason": "招待费标准用于超标准报销(R3)检测",
