        {"article": "第二条", "rule": "单次招待费上限", "threshold": "不超过5000元"},
        {"article": "第三条", "rule": "人均招待费上限", "threshold": "不超过300元"}
      ]
    },
    {
      "policy_id": "07_office_communication.md",
      "title": "XX证券办公与通讯费用管理办法",
      "doc_number": "XX证办规〔2025〕庚号",
      "effective_date": "2025-01-01",
      "expiry_date": null,
      "status": "current",
      "applicability_reason": "办公用品和通讯费标准用于超标准报销(R3)检测",
