        {"article": "第二条", "rule": "办公用品月度上限", "threshold": "每人每月不超过600元"},
        {"article": "第三条", "rule": "通讯费月度上限", "threshold": "每人每月不超过300元"}
      ]
    },
    {
      "policy_id": "08_budget_management.md",
      "title": "XX证券预算管理办法",
      "doc_number": "XX证财规〔2025〕辛号",
      "effective_date": "2025-01-01",
      "expiry_date": null,
      "status": "current",
      "applicability_reason": "预算管理办法用于超预算报销(R4)检测",
      "applicable_clauses": [
        {"article": "第二条", "rule": "预算约束", "threshold": "年度预算额度1.0倍"},
        {"article": "第三条", "rule": "超预算停止报销", "threshold": "达到1.0倍后不得继续报销"},
        {"article": "第四条", "rule": "超预算豁免", "threshold": "监管要求/客户服务/经营连续性+专项审批"}
      ]
    }
  ],
  "excluded_policies": [
    {
      "policy_id": "02_expense_reimbursement_2022_deprecated.md",
      "title": "XX证券费用报销管理办法(2022版)",
      "doc_number": "XX证财规〔2022〕乙号",
      "exclusion_reason": "已被2025修订版废止（第十四条）。2022版的审批金额已被后续制度替代，不得作为现行审批依据。审计期间为2025年全年，不适用。",
      "status": "repealed",
      "repealed_by": "01_expense_reimbursement_2025.md",
      "repeal_date": "2025-01-01"
    }
  ],
  "policy_transitions": [
    {
      "from": "02_expense_reimbursement_2022_deprecated.md",
      "to": "01_expense_reimbursement_2025.md",
      "transition_date": "2025-01-01",
      "type": "repeal_and_replace"
    }
  ],
  "exemptions_and_exceptions": [
    {
      "rule": "超标准报销",
      "exemption": "有专项审批(special_approval)的情况下可超过制度标准",
      "source": "01_expense_reimbursement_2025.md 第十二条"
    },
    {
      "rule": "超预算报销",
      "exemption": "因监管要求、客户服务或经营连续性需要+专项审批可超预算",
      "source": "08_budget_management.md 第四条"
    },
    {
      "rule": "超期报销",
      "exemption": "会计年度末发生的费用最迟可在财政年度结束后15天内补充提交",
      "source": "01_expense_reimbursement_2025.md 第九条"
    }
  ],
  "unresolved_items": []
}

